echo -e "${ORANGE}╔══════════════════════════════════════════════════════╗"
echo -e "║    PHOENIX OS — GITHUB MASS CLONE COMPLETE          ║"
echo -e "╠══════════════════════════════════════════════════════╣"
printf "║ ✓ Cloned:  %-42s║\n" "$PASS tools"
printf "║ ~ Skipped: %-42s║\n" "$SKIP already present"
printf "║ ✗ Failed:  %-42s║\n" "$FAIL dead/private repos"
printf "║   Total:   %-42s║\n" "$TOTAL processed"
echo -e "╚══════════════════════════════════════════════════════╝${NC}"
